import java.util.*;

public class TaskScheduler {

    public List<Integer> schedule(int tasks, int[][] deps) {
        // deps[i] = {prerequisite, task} meaning prerequisite must come before task
        int[] inDegree = new int[tasks];
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < tasks; i++) adj.add(new ArrayList<>());

        for (int[] d : deps) {
            adj.get(d[0]).add(d[1]);
            inDegree[d[1]]++;
        }

        Queue<Integer> queue = new LinkedList<>();
        // TODO: Enqueue all tasks with inDegree == 0

        List<Integer> order = new ArrayList<>();
        while (!queue.isEmpty()) {
            int curr = queue.poll();
            order.add(curr);
            // TODO: For each neighbor, decrement inDegree; if it becomes 0, enqueue
        }

        if (order.size() != tasks) return Collections.emptyList(); // cycle detected
        return order;
    }

    public static void main(String[] args) {
        TaskScheduler ts = new TaskScheduler();
        // 5 tasks: 0,1,2,3,4
        // deps: 0->1, 0->2, 1->3, 2->3, 3->4
        int[][] deps = {{0,1},{0,2},{1,3},{2,3},{3,4}};
        List<Integer> order = ts.schedule(5, deps);
        System.out.println("Execution order: " + order);

        // Cycle test
        int[][] cycle = {{0,1},{1,2},{2,0}};
        List<Integer> cycleResult = ts.schedule(3, cycle);
        System.out.println("Cyclic deps order: " + cycleResult);
    }
}

