public class BipartiteChecker {

    public boolean isBipartite(int V, List<Integer>[] adj) {
        int[] color = new int[V];
        Arrays.fill(color, -1); // -1 = uncolored

        for (int start = 0; start < V; start++) {
            if (color[start] != -1) continue; // already colored
            // TODO: BFS from 'start', coloring with 0/1 alternately
            //       If a neighbor has the same color as the current node, return false
        }
        return true;
    }

    @SuppressWarnings("unchecked")
    public static void main(String[] args) {
        // Bipartite graph: even-odd cycle (square)
        int V1 = 4;
        List<Integer>[] g1 = new ArrayList[V1];
        for (int i = 0; i < V1; i++) g1[i] = new ArrayList<>();
        int[][] e1 = {{0,1},{1,2},{2,3},{3,0}};
        for (int[] e : e1){ g1[e[0]].add(e[1]); g1[e[1]].add(e[0]); }

        // Non-bipartite: odd cycle (triangle)
        int V2 = 3;
        List<Integer>[] g2 = new ArrayList[V2];
        for (int i = 0; i < V2; i++) g2[i] = new ArrayList<>();
        int[][] e2 = {{0,1},{1,2},{2,0}};
        for (int[] e : e2){ g2[e[0]].add(e[1]); g2[e[1]].add(e[0]); }

        BipartiteChecker bc = new BipartiteChecker();
        System.out.println("Square is bipartite: " + bc.isBipartite(V1, g1));
        System.out.println("Triangle is bipartite: " + bc.isBipartite(V2, g2));
    }
}
